class Solution {
public:
    string discountPrices(string sentence, int discount) {
        stringstream ss(sentence);
        string word;
        string result = "";
        while (ss >> word) {
            if (word[0] == '$' && word.length() > 1 && isdigit(word[1])) {
                int price = stoi(word.substr(1));
                double discountedPrice = price * (100 - discount) / 100.0;
                char buffer[20];
                sprintf(buffer, "$%.2f", discountedPrice);
                result += buffer;
            } else {
                result += word;
            }
            result += " ";
        }
        result.pop_back();
        return result;
    }
};

